import { useMemo } from 'react';

/**
 * Tier hierarchy — Build Bible v2.0:
 * explorer < trader < pro < institutional
 * Each tier includes all permissions of lower tiers.
 */
const TIER_LEVELS = {
  explorer: 0,
  trader: 1,
  pro: 2,
  institutional: 3,
  // Legacy names → map to new tiers
  beginner: 0,
  free: 0,
  starter: 1,
  active: 2,
  operator: 2,
  elite: 3,
  power_user: 2,
  professional: 2,
};

/**
 * Route → minimum tier mapping.
 * Routes not listed default to 'explorer' (accessible to all).
 */
const ROUTE_TIERS = {
  // Trader tier
  '/orders': 'trader',
  '/scanners/momentum': 'trader',
  '/scanners/reversals': 'trader',
  '/scanners/volume': 'trader',
  '/scanners/sectors': 'trader',
  '/marketplace': 'trader',
  '/copy-trading': 'trader',
  '/options': 'trader',
  '/multi-leg-orders': 'trader',
  '/journal': 'trader',
  '/tax-report': 'pro',

  // Pro tier
  '/research': 'pro',
  '/research/regime': 'pro',
  '/research/promotions': 'pro',
  '/research/portfolio': 'pro',
  '/research/sweep': 'pro',
  '/strategy-lab': 'pro',
  '/ml-analytics': 'pro',
  '/alpha-factory': 'pro',
  '/strategy-genome': 'pro',
  '/strategy-lifecycle': 'pro',
  '/bot-management': 'pro',
  '/risk/dynamic': 'pro',
  '/arbitrage': 'pro',
  '/microstructure': 'pro',
  '/execution-algos': 'pro',
  '/order-flow': 'pro',
  '/execution-analytics': 'pro',
  '/factor-attribution': 'pro',
  '/walk-forward': 'pro',
  '/recommendations': 'pro',

  // Institutional tier
  '/api-keys': 'institutional',
  '/developer-portal': 'institutional',
  '/mission-control': 'institutional',
  '/self-healing': 'institutional',
  '/operator-events': 'institutional',
  '/policy-simulator': 'institutional',
  '/system-health': 'institutional',
  '/emergency': 'institutional',
  '/data-pipeline': 'institutional',
  '/pipeline-monitor': 'institutional',
  '/capital-allocation': 'institutional',
  '/audit': 'institutional',
  '/logs': 'institutional',
  '/permissions': 'institutional',
  '/user-management': 'institutional',
  '/admin/analytics': 'institutional',
  '/system-settings': 'institutional',
  '/strategy-decay': 'institutional',
  '/operator/regime-risk': 'institutional',
  '/operator/execution-infra': 'institutional',
  '/operator/ml-deploy': 'institutional',
  '/operator/control': 'institutional',
};

/**
 * Get the current user's tier from auth context.
 * Falls back to 'institutional' for development (all access).
 */
// Founder emails — always get full institutional access, no gates
const FOUNDER_EMAILS = new Set(['shawn@auraalpha.cc', 'shawngallup@hotmail.com', 'sgallup23@gmail.com', 'sgallup@icloud.com']);

function getUserTier() {
  const fallback = import.meta.env.DEV ? 'institutional' : 'explorer';
  try {
    const raw = localStorage.getItem('aura_user');
    if (!raw) return fallback;
    const user = JSON.parse(raw);
    // Founders bypass all tier gates
    const email = (user.email || '').toLowerCase();
    if (FOUNDER_EMAILS.has(email)) return 'institutional';
    const tier = user.tier || user.subscription_tier || fallback;
    // Resolve legacy names
    if (tier === 'free' || tier === 'beginner') return 'explorer';
    if (tier === 'starter') return 'trader';
    if (tier === 'active' || tier === 'professional') return 'pro';
    if (tier === 'power_user' || tier === 'operator') return 'pro';
    if (tier === 'elite') return 'institutional';
    return tier;
  } catch {
    return fallback;
  }
}

/**
 * Get the required tier for a given route path.
 */
function getRequiredTier(path) {
  // Exact match first
  if (ROUTE_TIERS[path]) return ROUTE_TIERS[path];
  // Prefix match (for /research/*, /v2/*, etc.)
  for (const [route, tier] of Object.entries(ROUTE_TIERS)) {
    if (path.startsWith(route + '/')) return tier;
  }
  return 'explorer';
}

/**
 * Check if a tier level meets the required minimum.
 */
function tierMeetsRequirement(userTier, requiredTier) {
  return (TIER_LEVELS[userTier] ?? 0) >= (TIER_LEVELS[requiredTier] ?? 0);
}

/**
 * Hook: useTierGate
 *
 * Returns:
 *   userTier       - current user's tier string
 *   hasAccess(path) - check if user can access a given route
 *   requiredTier(path) - get the minimum tier for a route
 *   canAccess      - boolean for a specific path (if provided)
 *   tierLabel      - human-readable tier name
 */
export default function useTierGate(path) {
  const userTier = getUserTier();

  const result = useMemo(() => {
    const required = path ? getRequiredTier(path) : 'explorer';
    const canAccess = tierMeetsRequirement(userTier, required);

    return {
      userTier,
      canAccess,
      requiredTier: required,
      tierLabel: {
        explorer: 'Explorer',
        trader: 'Trader',
        pro: 'Pro',
        institutional: 'Institutional',
      }[required] || required,
      hasAccess: (p) => tierMeetsRequirement(userTier, getRequiredTier(p)),
      getRequiredTier,
    };
  }, [userTier, path]);

  return result;
}

export { TIER_LEVELS, ROUTE_TIERS, getUserTier, getRequiredTier, tierMeetsRequirement };
